-- Patchnote 0.7.4 — idempotent seed (ON CONFLICT DO NOTHING).
INSERT INTO "Patchnote" ("version", "type", "date", "titleEn", "titleFr", "entries") VALUES
('0.7.4', 'minor', '2026-04-26T00:00:00.000Z',
  'Multi-tab dashboard + plugin install via release assets',
  'Dashboard multi-onglets + install plugin via assets de release',
  '[{"type":"feat","titleEn":"Multi-tab admin dashboard","titleFr":"Dashboard admin multi-onglets","descEn":"The dashboard now hosts multiple named tabs. Add a tab with the + button, double-click a tab to rename, or remove the active one in edit mode (the last remaining tab is locked so you''re never empty). Widgets live on the active tab and are still unique across the whole layout.","descFr":"Le dashboard accueille maintenant plusieurs onglets nommés. Ajoute un onglet via le bouton +, double-clique pour renommer, ou supprime l''onglet actif en mode édition (le dernier onglet est verrouillé pour ne jamais te retrouver vide). Les widgets vivent sur l''onglet actif et restent uniques sur l''ensemble du layout."},{"type":"ui","titleEn":"Reset confirm modal","titleFr":"Modal de confirmation Reset","descEn":"The Reset-to-default action moved out of the toolbar into a proper a11y-aware modal (Escape, focus-trap, focus-return) and only renders in edit mode where it belongs.","descFr":"L''action Réinitialiser quitte la toolbar pour une vraie modal accessible (Escape, piège de focus, retour de focus) — visible uniquement en mode édition."},{"type":"fix","titleEn":"Plugin install respects release assets","titleFr":"L''install plugin respecte les assets de release","descEn":"Installing from the Discover tab used to hardcode tarball/HEAD — GitHub''s auto-generated source archive that omits gitignored build outputs. For plugins that ship dist/ as a Release asset (the recommended pattern), the install would land an unbuilt tree and fail. Oscarr now resolves the install URL via the GitHub Releases API: first .tar.gz asset on the latest release wins, with a fallback to tarball/HEAD for plugins that still commit dist/ to their repo.","descFr":"L''install depuis l''onglet Découvrir hardcodait tarball/HEAD — l''archive source auto-générée par GitHub qui exclut les artefacts de build gitignorés. Pour les plugins qui livrent dist/ via un asset de Release (le pattern recommandé), l''install récupérait un arbre non buildé et plantait. Oscarr résout maintenant l''URL d''install via l''API GitHub Releases : le premier asset .tar.gz de la dernière release gagne, avec un fallback sur tarball/HEAD pour les plugins qui committent encore dist/ dans leur repo."},{"type":"docs","titleEn":"Plugin release workflow template","titleFr":"Template de workflow de release plugin","descEn":"docs/plugins.md gains a Releasing a plugin section with a copy-paste GitHub Actions workflow that builds, packs and uploads a tarball asset on every v* tag — so future plugin authors land on the asset path by default and stop polluting their git history with built code.","descFr":"docs/plugins.md gagne une section Releasing a plugin avec un workflow GitHub Actions copy-paste qui build, packe et upload un asset tarball à chaque tag v* — les futurs plugin authors atterrissent par défaut sur le bon pattern et arrêtent de polluer leur historique git avec du code buildé."}]'
) ON CONFLICT ("version") DO NOTHING;
